mapper.select:
SELECT p.userId as userId, COUNT(DISTINCT p.id) as contentCount, COALESCE(SUM(p.viewCount), 0) as totalViewCount, COALESCE(SUM(p.likeCount), 0) as totalLikeCount, COALESCE(SUM(p.commentCount), 0) as totalCommentCount, COALESCE(SUM(p.favoriteCount), 0) as totalFavoriteCount, COALESCE(SUM(p.shareCount), 0) as totalShareCount, MAX(p.createTime) as lastPublishTime, COUNT(DISTINCT DATE(p.createTime)) as activeDays FROM picture p WHERE p.isDelete = 0 AND p.reviewStatus = 1 AND p.isDraft = 0 AND p.spaceId IS NULL
AND p.createTime >= #{startTime}
AND p.createTime <= #{endTime}
GROUP BY p.userId HAVING contentCount > 0

SELECT p.userId as userId, COUNT(DISTINCT p.id) as contentCount, COALESCE(SUM(p.viewCount), 0) as totalViewCount, COALESCE(SUM(p.likeCount), 0) as totalLikeCount, COALESCE(SUM(p.commentCount), 0) as totalCommentCount, COALESCE(SUM(p.favoriteCount), 0) as totalFavoriteCount, COALESCE(SUM(p.shareCount), 0) as totalShareCount, MAX(p.createTime) as lastPublishTime, COUNT(DISTINCT DATE(p.createTime)) as activeDays FROM post p WHERE p.isDelete = 0 AND p.status = 1 AND p.isDraft = 0
AND p.createTime >= #{startTime}
AND p.createTime <= #{endTime}
GROUP BY p.userId HAVING contentCount > 0
